import{_ as t,o as h,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"Tồn kho đầu kỳ","description":"","frontmatter":{"title":"Tồn kho đầu kỳ"},"headers":[],"relativePath":"opening-stock.md","filePath":"opening-stock.md"}'),a={name:"opening-stock.md"};function c(l,n,u,r,e,g){return h(),o("div",null,[...n[0]||(n[0]=[i('<h1 id="ton-kho-đau-ky" tabindex="-1">Tồn kho đầu kỳ <a class="header-anchor" href="#ton-kho-đau-ky" aria-label="Permalink to &quot;Tồn kho đầu kỳ&quot;">​</a></h1><p><strong>Tồn kho đầu kỳ (Opening Stock)</strong> là số lượng hàng tồn kho thực tế tại thời điểm bắt đầu sử dụng ABNERP. Việc thiết lập chính xác số dư tồn kho đầu kỳ là bước quan trọng để đảm bảo số liệu kế toán và quản lý kho chính xác ngay từ đầu.</p><h2 id="khi-nao-can-thiet-lap" tabindex="-1">Khi nào cần thiết lập? <a class="header-anchor" href="#khi-nao-can-thiet-lap" aria-label="Permalink to &quot;Khi nào cần thiết lập?&quot;">​</a></h2><p>Thiết lập tồn kho đầu kỳ cần thực hiện trong các trường hợp sau:</p><ul><li><strong>Triển khai ABNERP lần đầu</strong>: chuyển đổi từ hệ thống cũ hoặc từ quản lý thủ công sang ABNERP</li><li><strong>Đầu năm tài chính mới</strong>: nhập số dư tồn kho đầu kỳ cho năm tài chính</li><li><strong>Thêm kho mới</strong>: khi mở thêm kho hoặc chi nhánh mới</li><li><strong>Sau kiểm kê</strong>: cập nhật số dư thực tế sau khi kiểm kê kho</li></ul><h2 id="quy-trinh-thiet-lap" tabindex="-1">Quy trình thiết lập <a class="header-anchor" href="#quy-trinh-thiet-lap" aria-label="Permalink to &quot;Quy trình thiết lập&quot;">​</a></h2><h3 id="buoc-1-chuan-bi-du-lieu" tabindex="-1">Bước 1: Chuẩn bị dữ liệu <a class="header-anchor" href="#buoc-1-chuan-bi-du-lieu" aria-label="Permalink to &quot;Bước 1: Chuẩn bị dữ liệu&quot;">​</a></h3><p>Lập danh sách tất cả mặt hàng hiện có trong kho với các thông tin:</p><ul><li>Mã mặt hàng và tên mặt hàng (khớp với mã hàng trong hệ thống)</li><li>Số lượng tồn thực tế</li><li>Đơn vị tính</li><li>Giá vốn bình quân hoặc giá nhập cuối</li><li>Kho chứa hàng</li></ul><h3 id="buoc-2-su-dung-cong-cu-nhap-kho-đau-ky" tabindex="-1">Bước 2: Sử dụng công cụ Nhập kho đầu kỳ <a class="header-anchor" href="#buoc-2-su-dung-cong-cu-nhap-kho-đau-ky" aria-label="Permalink to &quot;Bước 2: Sử dụng công cụ Nhập kho đầu kỳ&quot;">​</a></h3><p>Vào <strong>Kho &gt; Công cụ &gt; Nhập số dư đầu kỳ</strong> và chọn <strong>Nhập tồn kho đầu kỳ (Opening Stock Entry)</strong>. Có hai cách thực hiện:</p><ul><li><strong>Nhập thủ công</strong>: thêm từng mặt hàng, số lượng và giá trị vào bảng</li><li><strong>Nhập từ tệp</strong>: tải mẫu Excel, điền dữ liệu và nhập hàng loạt</li></ul><h3 id="buoc-3-xac-nhan-va-hach-toan" tabindex="-1">Bước 3: Xác nhận và hạch toán <a class="header-anchor" href="#buoc-3-xac-nhan-va-hach-toan" aria-label="Permalink to &quot;Bước 3: Xác nhận và hạch toán&quot;">​</a></h3><p>Sau khi nhập đầy đủ thông tin, hệ thống sẽ tạo một <strong>Phiếu nhập kho (Stock Entry)</strong> với loại &quot;Nhập kho đầu kỳ&quot;. Phiếu này sẽ:</p><ul><li>Cập nhật số dư tồn kho cho từng mặt hàng và từng kho</li><li>Hạch toán giá trị tồn kho tương ứng vào tài khoản kế toán hàng tồn kho</li><li>Ghi nhận bút toán đối ứng vào tài khoản &quot;Chênh lệch tồn kho đầu kỳ&quot;</li></ul><h3 id="xac-minh-so-du" tabindex="-1">Xác minh số dư <a class="header-anchor" href="#xac-minh-so-du" aria-label="Permalink to &quot;Xác minh số dư&quot;">​</a></h3><p>Sau khi nhập, kiểm tra lại bằng cách:</p><ol><li>Vào <strong>Kho &gt; Báo cáo &gt; Số dư kho (Stock Balance Report)</strong></li><li>So sánh số lượng và giá trị hiển thị với số liệu thực tế</li><li>Kiểm tra bút toán kế toán trong <strong>Sổ cái (General Ledger)</strong></li></ol><blockquote><p><strong>Lưu ý</strong>: Nếu phát hiện sai sót, có thể hủy bỏ (Cancel) phiếu nhập tồn kho đầu kỳ và tạo lại. Không nên sửa trực tiếp số dư tồn kho — hãy dùng công cụ này để đảm bảo tính nhất quán và kiểm toán được.</p></blockquote>',19)])])}const p=t(a,[["render",c]]);export{s as __pageData,p as default};
